"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["90181"],{11178(e){e.exports=JSON.parse('{"tag":{"label":"Temporal CLI","permalink":"/tags/temporal-cli","allTagsPath":"/tags","count":12,"items":[{"id":"cli/activity","title":"Temporal CLI activity command reference","description":"Learn how to use Temporal Activity commands for completing or failing Activity Executions in your Workflow. Optimize your Temporal Workflow management effectively.","permalink":"/cli/activity"},{"id":"cli/batch","title":"Temporal CLI batch command reference","description":"Use Temporal CLI to manage multiple Workflow Executions with Batch Jobs that can Cancel, Signal, or Terminate Workflows. Filter and monitor Batch Jobs effectively.","permalink":"/cli/batch"},{"id":"cli/cmd-options","title":"Temporal CLI command options reference","description":"Discover how to manage Temporal Workflows, from Activity Execution to Workflow Ids, using clusters, cron schedules, dynamic configurations, and logging. Perfect for developers.","permalink":"/cli/cmd-options"},{"id":"cli/index","title":"Temporal CLI command reference","description":"The Temporal CLI offers terminal access to Temporal Services for managing, monitoring, and debugging Workflows and Activities, including Namespace and Task Queue management, with embedded development support.","permalink":"/cli"},{"id":"cli/config","title":"Temporal CLI config command reference","description":"Temporal CLI \'config\' commands allow the getting, setting, deleting, and listing of configuration properties for connecting to Temporal.","permalink":"/cli/config"},{"id":"cli/env","title":"Temporal CLI env command reference","description":"Temporal CLI \'env\' commands allow the configuration, setting, deleting, and listing of environmental properties, making it easy to manage Temporal Server instances.","permalink":"/cli/env"},{"id":"cli/operator","title":"Temporal CLI operator command reference","description":"Operator commands in Temporal allow actions on Namespaces, Search Attributes, Clusters and Nexus Endpoints using specific subcommands. Execute with \\"temporal operator [command] [subcommand] [options]\\".","permalink":"/cli/operator"},{"id":"cli/schedule","title":"Temporal CLI schedule command reference","description":"Temporal\'s Schedule commands allow users to create, update, and manage Workflow Executions seamlessly for automation, supporting commands for creation, backfill, deletion, and more.","permalink":"/cli/schedule"},{"id":"cli/server","title":"Temporal CLI server command reference","description":"Manage your Temporal Server easily with CLI commands. Start a local server using `temporal server start-dev` and access the Web UI at http://localhost:8233. Customize with multiple options.","permalink":"/cli/server"},{"id":"cli/task-queue","title":"Temporal CLI task-queue command reference","description":"Temporal Task Queue commands facilitate operations like describing poller info, displaying partitions, fetching compatible Build IDs, and determining Build ID reachability for effective Workflow and Activity management.","permalink":"/cli/task-queue"},{"id":"cli/worker","title":"Temporal CLI worker command reference","description":"Learn how to read or modify state associated with a Worker, such as Worker Deployments.","permalink":"/cli/worker"},{"id":"cli/workflow","title":"Temporal CLI workflow command reference","description":"Temporal Workflow commands enable operations on Workflow Executions, such as cancel, count, delete, describe, execute, list, update-options, query, reset, reset-batch, show, signal, stack, start, terminate, trace, and update, enhancing efficiency and control.","permalink":"/cli/workflow"}],"unlisted":false}}')}}]);